mapper.select:
SELECT r.accommodation_id, rb.room_id, rb.start_date, rb.end_date FROM room_blocks rb JOIN rooms r ON r.room_id = rb.room_id WHERE rb.status = 'ACTIVE' AND rb.start_date < #{endDate} AND rb.end_date >= #{startDate} AND r.accommodation_id IN
#{accommodationId}
ORDER BY r.accommodation_id, rb.room_id, rb.start_date, rb.end_date

SELECT rv.accommodation_id, rn.assigned_room_id AS room_id, rn.stay_date FROM reservation_nights rn JOIN reservations rv ON rv.reservation_id = rn.reservation_id WHERE rv.accommodation_id IN
#{accommodationId}
AND rn.stay_date >= #{startDate} AND rn.stay_date < #{endDate} AND rv.status IN ('PENDING', 'CONFIRMED') ORDER BY rv.accommodation_id, rn.stay_date, rn.assigned_room_id

SELECT rn.reservation_night_id, rn.reservation_id, rn.stay_date, rn.assigned_room_id, r.room_code AS assigned_room_code, r.room_type_id AS assigned_room_type_id, rt.name AS assigned_room_type_name FROM reservation_nights rn JOIN rooms r ON r.room_id = rn.assigned_room_id JOIN room_types rt ON rt.room_type_id = r.room_type_id WHERE rn.reservation_id IN
#{reservationId}
ORDER BY rn.reservation_id ASC, rn.stay_date ASC, rn.reservation_night_id ASC
